package logger

import (
	"io"
	"log"
	"os"
	"path/filepath"
	"regexp"
	"runtime"
	"sort"
	"strconv"
	"strings"
	"time"
)

const (
	FieldAddress    = "address"
	FieldComponent  = "component"
	FieldDurationMS = "duration_ms"
	FieldError      = "error"
	FieldErrorType  = "error_type"
	FieldException  = "exception_recorded"
	FieldMethod     = "method"
	FieldOperation  = "operation"
	FieldPath       = "path"
	FieldRequestID  = "request_id"
	FieldSource     = "source"
	FieldSpanID     = "span_id"
	FieldStatusCode = "status_code"
	FieldTraceFlags = "trace_flags"
	FieldTraceID    = "trace_id"

	redactedValue = "[REDACTED]"
)

var (
	keyValueSecretPattern = regexp.MustCompile(`(?i)("?(?:password|passwd|pwd|token|secret|api[_-]?key|apikey|authorization|cookie|set-cookie)"?\s*[:=]\s*)("[^"]*"|'[^']*'|[^\s,;]+)`)
	bearerSecretPattern   = regexp.MustCompile(`(?i)\bBearer\s+[^\s",;]+`)
)

// Field is a single stable runtime log field.
type Field struct {
	Key   string
	Value string
}

// RuntimeLogger is the concrete backend runtime log adapter.
type RuntimeLogger struct {
	sink *log.Logger
	exit func(int)
}

var standard = newRuntimeLogger(os.Stdout, os.Exit)

// New creates a logger that writes runtime logs to output.
func New(output io.Writer) *RuntimeLogger {
	return newRuntimeLogger(output, os.Exit)
}

func newRuntimeLogger(output io.Writer, exit func(int)) *RuntimeLogger {
	if output == nil {
		output = os.Stdout
	}
	if exit == nil {
		exit = os.Exit
	}

	return &RuntimeLogger{
		sink: log.New(output, "", log.LstdFlags),
		exit: exit,
	}
}

// Standard returns the shared process logger used by package-level helpers.
func Standard() *RuntimeLogger {
	return standard
}

// String creates a normalized string field.
func String(key, value string) Field {
	return Field{
		Key:   normalizeKey(key),
		Value: value,
	}
}

// Address records a listening or remote address using the stable runtime key.
func Address(value string) Field {
	return String(FieldAddress, value)
}

// DurationMS records a duration in whole milliseconds.
func DurationMS(value time.Duration) Field {
	return String(FieldDurationMS, strconv.FormatInt(value.Milliseconds(), 10))
}

// Method records an HTTP method for request-boundary logs.
func Method(value string) Field {
	return String(FieldMethod, value)
}

// Operation records the runtime operation name for startup, server, or middleware logs.
func Operation(value string) Field {
	return String(FieldOperation, value)
}

// Path records an HTTP path for request-boundary logs.
func Path(value string) Field {
	return String(FieldPath, value)
}

// RequestID records the boundary-generated or propagated request identifier.
func RequestID(value string) Field {
	return String(FieldRequestID, value)
}

// Err records an error value using the stable runtime key.
func Err(err error) Field {
	if err == nil {
		return Field{}
	}

	return String(FieldError, err.Error())
}

// ErrorType records a stable OpenTelemetry-aligned failure classification.
func ErrorType(value string) Field {
	return String(FieldErrorType, value)
}

// ExceptionRecorded marks the single runtime log line that recorded an exception.
func ExceptionRecorded() Field {
	return String(FieldException, "true")
}

// TraceContext adds explicit OpenTelemetry-aligned correlation fields when available.
// It intentionally stops at log-field correlation; provider and exporter wiring stays
// outside this package until a later runtime observability rollout.
func TraceContext(traceID, spanID, traceFlags string) []Field {
	fields := make([]Field, 0, 3)

	traceID = strings.ToLower(strings.TrimSpace(traceID))
	if validTraceID(traceID) {
		fields = append(fields, String(FieldTraceID, traceID))
	}

	spanID = strings.ToLower(strings.TrimSpace(spanID))
	if validSpanID(spanID) {
		fields = append(fields, String(FieldSpanID, spanID))
	}

	traceFlags = strings.ToLower(strings.TrimSpace(traceFlags))
	if validHex(traceFlags, 2) {
		fields = append(fields, String(FieldTraceFlags, traceFlags))
	}

	return fields
}

// TraceContextFromTraceparent extracts OTel-aligned trace fields from a W3C traceparent header.
// It preserves request-boundary correlation without turning stdout logging into the
// tracing or exporter contract.
func TraceContextFromTraceparent(traceparent string) []Field {
	traceparent = strings.TrimSpace(traceparent)
	if traceparent == "" {
		return nil
	}

	parts := strings.Split(traceparent, "-")
	if len(parts) != 4 || !validHex(strings.ToLower(parts[0]), 2) {
		return nil
	}
	if !validTraceID(strings.ToLower(parts[1])) || !validSpanID(strings.ToLower(parts[2])) || !validHex(strings.ToLower(parts[3]), 2) {
		return nil
	}

	return []Field{
		String(FieldTraceID, strings.ToLower(parts[1])),
		String(FieldSpanID, strings.ToLower(parts[2])),
		String(FieldTraceFlags, strings.ToLower(parts[3])),
	}
}

// StatusCode records an HTTP status code for request-boundary logs.
func StatusCode(value int) Field {
	return String(FieldStatusCode, strconv.Itoa(value))
}

// Info writes an informational runtime log entry.
func Info(component, message string, fields ...Field) {
	standard.log(3, "INFO", component, message, fields...)
}

// Warn writes a warning runtime log entry.
func Warn(component, message string, fields ...Field) {
	standard.log(3, "WARN", component, message, fields...)
}

// Error writes an error runtime log entry.
func Error(component, message string, err error, fields ...Field) {
	fields = append(fields, Err(err))
	standard.log(3, "ERROR", component, message, fields...)
}

// Fatal writes a fatal runtime log entry and exits the process.
func Fatal(component, message string, err error, fields ...Field) {
	fields = append(fields, Err(err))
	standard.log(3, "FATAL", component, message, fields...)
	standard.exit(1)
}

// Info writes an informational runtime log entry.
func (l *RuntimeLogger) Info(component, message string, fields ...Field) {
	l.log(3, "INFO", component, message, fields...)
}

// Warn writes a warning runtime log entry.
func (l *RuntimeLogger) Warn(component, message string, fields ...Field) {
	l.log(3, "WARN", component, message, fields...)
}

// Error writes an error runtime log entry.
func (l *RuntimeLogger) Error(component, message string, err error, fields ...Field) {
	fields = append(fields, Err(err))
	l.log(3, "ERROR", component, message, fields...)
}

// Fatal writes a fatal runtime log entry and exits the process.
func (l *RuntimeLogger) Fatal(component, message string, err error, fields ...Field) {
	fields = append(fields, Err(err))
	l.log(3, "FATAL", component, message, fields...)
	l.exit(1)
}

// LogInfo retains the older call shape while emitting the stable runtime vocabulary.
func LogInfo(context, function, message string) {
	standard.log(3, "INFO", context, message, Operation(function))
}

// LogWarn retains the older call shape while emitting the stable runtime vocabulary.

package runtime

import "sync/atomic"

// Readiness tracks whether the process should receive traffic.
type Readiness struct {
	ready atomic.Bool
}

func NewReadiness() *Readiness {
	return &Readiness{}
}

func (r *Readiness) MarkReady() {
	if r == nil {
		return
	}
	r.ready.Store(true)
}

func (r *Readiness) MarkNotReady() {
	if r == nil {
		return
	}
	r.ready.Store(false)
}

func (r *Readiness) Ready() bool {
	if r == nil {
		return false
	}
	return r.ready.Load()
}

package logger

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"errors"
	"fmt"
	"net/http"
	"strings"
	"time"
)

const (
	RequestIDHeader           = "X-Request-Id"
	clientClosedRequestStatus = 499

	requestIDContextKey contextKey = "request_id"
	traceIDContextKey   contextKey = "trace_id"
	spanIDContextKey    contextKey = "span_id"
)

type contextKey string

// RequestIDFromContext retrieves the current request id from context when present.
func RequestIDFromContext(ctx context.Context) string {
	return contextValue(ctx, requestIDContextKey)
}

// TraceIDFromContext retrieves the current trace id from context when present.
func TraceIDFromContext(ctx context.Context) string {
	return contextValue(ctx, traceIDContextKey)
}

// SpanIDFromContext retrieves the current span id from context when present.
func SpanIDFromContext(ctx context.Context) string {
	return contextValue(ctx, spanIDContextKey)
}

func contextValue(ctx context.Context, key contextKey) string {
	if ctx == nil {
		return ""
	}
	value, _ := ctx.Value(key).(string)
	return value
}

// ContextWithRequestCorrelation attaches the request-boundary correlation fields
// used by runtime logging and legacy handler diagnostics.
func ContextWithRequestCorrelation(ctx context.Context, requestID, traceparent string) context.Context {
	if ctx == nil {
		ctx = context.Background()
	}

	requestID = strings.TrimSpace(requestID)
	if requestID != "" {
		ctx = context.WithValue(ctx, requestIDContextKey, requestID)
	}

	traceID, spanID := parseTraceparent(traceparent)
	if traceID != "" {
		ctx = context.WithValue(ctx, traceIDContextKey, traceID)
	}
	if spanID != "" {
		ctx = context.WithValue(ctx, spanIDContextKey, spanID)
	}

	return ctx
}

// RequestLoggingMiddleware logs one completion line per request and propagates
// stable request/correlation identifiers at the runtime boundary.
func RequestLoggingMiddleware(next http.Handler) http.Handler {
	if next == nil {
		return http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
			http.Error(w, "handler unavailable", http.StatusInternalServerError)
		})
	}

	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		requestID := strings.TrimSpace(r.Header.Get(RequestIDHeader))
		if requestID == "" {
			requestID = newRequestID()
		}

		traceID, spanID := parseTraceparent(r.Header.Get("traceparent"))
		ctx := ContextWithRequestCorrelation(r.Context(), requestID, r.Header.Get("traceparent"))

		r = r.WithContext(ctx)

		recorder := &statusRecorder{ResponseWriter: w, statusCode: http.StatusOK}
		recorder.Header().Set(RequestIDHeader, requestID)

		next.ServeHTTP(recorder, r)

		statusCode := recorder.statusCode
		canceled := isRequestCanceled(r.Context().Err())
		if canceled && !recorder.wroteHeader {
			statusCode = clientClosedRequestStatus
		}

		duration := time.Since(start).Milliseconds()
		message := fmt.Sprintf(
			"method=%s path=%s status=%d duration_ms=%d request_id=%s trace_id=%s span_id=%s remote_addr=%s",
			r.Method,
			r.URL.Path,
			statusCode,
			duration,
			requestID,
			orDash(traceID),
			orDash(spanID),
			orDash(remoteAddress(r)),
		)

		switch {
		case canceled && !recorder.wroteHeader:
			LogWarn("HTTPRequest", "Canceled", message)
		case statusCode >= http.StatusInternalServerError:
			LogError("HTTPRequest", "Complete", errors.New(message))
		case statusCode >= http.StatusBadRequest:
			LogWarn("HTTPRequest", "Complete", message)
		default:
			LogInfo("HTTPRequest", "Complete", message)
		}
	})
}

type statusRecorder struct {
	http.ResponseWriter
	statusCode  int
	wroteHeader bool
}

func (w *statusRecorder) WriteHeader(statusCode int) {
	w.statusCode = statusCode
	w.wroteHeader = true
	w.ResponseWriter.WriteHeader(statusCode)
}

func (w *statusRecorder) Write(b []byte) (int, error) {
	if !w.wroteHeader {
		w.wroteHeader = true
	}
	return w.ResponseWriter.Write(b)
}

func isRequestCanceled(err error) bool {
	return errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)
}

func newRequestID() string {
	buf := make([]byte, 16)
	if _, err := rand.Read(buf); err != nil {
		return fmt.Sprintf("fallback-%d", time.Now().UnixNano())
	}
	return hex.EncodeToString(buf)
}

func parseTraceparent(header string) (traceID string, spanID string) {
	parts := strings.Split(strings.TrimSpace(header), "-")
	if len(parts) != 4 {
		return "", ""
	}

	if len(parts[1]) == 32 {
		traceID = parts[1]
	}
	if len(parts[2]) == 16 {
		spanID = parts[2]
	}

	return traceID, spanID
}

func orDash(value string) string {
	if strings.TrimSpace(value) == "" {
		return "-"
	}
	return value
}

func remoteAddress(r *http.Request) string {
	if r == nil {
		return ""
	}
	if forwardedFor := strings.TrimSpace(r.Header.Get("X-Forwarded-For")); forwardedFor != "" {
		return forwardedFor
	}
	if realIP := strings.TrimSpace(r.Header.Get("X-Real-Ip")); realIP != "" {
		return realIP
	}
	return r.RemoteAddr
}

package runtime

import (
	"context"
	"fmt"

	"gorm.io/gorm"
)

// ServingProbe owns process liveness and request-serving readiness checks.
type ServingProbe struct {
	db        *gorm.DB
	readiness *Readiness
}

func NewServingProbe(db *gorm.DB, readiness *Readiness) ServingProbe {
	return ServingProbe{db: db, readiness: readiness}
}

func (p ServingProbe) Live() bool {
	return true
}

func (p ServingProbe) Ready(ctx context.Context) error {
	if p.readiness == nil || !p.readiness.Ready() {
		return fmt.Errorf("startup readiness gate closed")
	}
	if err := CheckDBReadiness(ctx, p.db); err != nil {
		return err
	}
	return nil
}

package runtime

import (
	"context"
	"fmt"
	"log"
	"os"
	"strconv"
	"strings"
	"sync"
	"time"

	"gorm.io/driver/postgres"
	"gorm.io/gorm"
	gormlogger "gorm.io/gorm/logger"
)

var (
	db   *gorm.DB
	dbMu sync.RWMutex
)

// DBConfig holds the normalized database configuration.
type DBConfig struct {
	Host     string
	Port     string
	User     string
	Password string
	Name     string
	SSLMode  string
	TimeZone string

	MaxOpenConns    int
	MaxIdleConns    int
	ConnMaxLifetime time.Duration
	ConnMaxIdleTime time.Duration
	RequireTLS      bool
}

// DBFactory provides a hook to open a database using a given configuration.
type DBFactory interface {
	Open(DBConfig) (*gorm.DB, error)
}

// PostgresFactory implements DBFactory using the postgres driver.
type PostgresFactory struct {
	GormConfig *gorm.Config
}

// LoadDBConfigFromEnv normalizes env vars into a DBConfig.
func LoadDBConfigFromEnv() (DBConfig, error) {
	cfg := DBConfig{
		Host:            firstNonEmpty(os.Getenv("DB_HOST"), os.Getenv("DBHOST")),
		User:            firstNonEmpty(os.Getenv("POSTGRES_USER"), os.Getenv("DB_USER")),
		Password:        firstNonEmpty(os.Getenv("POSTGRES_PASSWORD"), os.Getenv("DB_PASS"), os.Getenv("DB_PASSWORD")),
		Name:            firstNonEmpty(os.Getenv("POSTGRES_DATABASE"), os.Getenv("POSTGRES_DB"), os.Getenv("DB_NAME")),
		Port:            firstNonEmpty(os.Getenv("POSTGRES_PORT"), os.Getenv("DB_PORT"), "5432"),
		SSLMode:         firstNonEmpty(os.Getenv("DB_SSLMODE"), os.Getenv("POSTGRES_SSLMODE"), os.Getenv("PGSSLMODE"), "disable"),
		TimeZone:        firstNonEmpty(os.Getenv("DB_TIMEZONE"), os.Getenv("PGTZ"), "UTC"),
		MaxOpenConns:    intFromEnv(25, "DB_MAX_OPEN_CONNS", "POSTGRES_MAX_OPEN_CONNS"),
		MaxIdleConns:    intFromEnv(5, "DB_MAX_IDLE_CONNS", "POSTGRES_MAX_IDLE_CONNS"),
		ConnMaxLifetime: durationFromEnv(30*time.Minute, "DB_CONN_MAX_LIFETIME", "POSTGRES_CONN_MAX_LIFETIME"),
		ConnMaxIdleTime: durationFromEnv(5*time.Minute, "DB_CONN_MAX_IDLE_TIME", "POSTGRES_CONN_MAX_IDLE_TIME"),
		RequireTLS:      boolFromEnv(isProductionRuntime(), "DB_REQUIRE_TLS", "POSTGRES_REQUIRE_TLS"),
	}

	if cfg.Host == "" {
		return DBConfig{}, fmt.Errorf("missing DB host (DB_HOST or DBHOST)")
	}
	if cfg.User == "" {
		return DBConfig{}, fmt.Errorf("missing DB user (POSTGRES_USER or DB_USER)")
	}
	if cfg.Name == "" {
		return DBConfig{}, fmt.Errorf("missing DB name (POSTGRES_DATABASE/POSTGRES_DB/DB_NAME)")
	}

	return cfg, nil
}

// BuildPostgresDSN assembles the postgres DSN from config.
func BuildPostgresDSN(cfg DBConfig) (string, error) {
	cfg.Host = strings.TrimSpace(cfg.Host)
	cfg.User = strings.TrimSpace(cfg.User)
	cfg.Name = strings.TrimSpace(cfg.Name)
	cfg.Port = strings.TrimSpace(cfg.Port)
	cfg.SSLMode = strings.ToLower(strings.TrimSpace(cfg.SSLMode))
	cfg.TimeZone = strings.TrimSpace(cfg.TimeZone)

	if cfg.Host == "" || cfg.User == "" || cfg.Name == "" {
		return "", fmt.Errorf("invalid DB config: host/user/name required")
	}

	port := cfg.Port
	if port == "" {
		port = "5432"
	}

	sslMode := cfg.SSLMode
	if sslMode == "" {
		sslMode = "disable"
	}
	if err := validateSSLMode(sslMode, cfg.RequireTLS); err != nil {
		return "", err
	}

	timeZone := cfg.TimeZone
	if timeZone == "" {
		timeZone = "UTC"
	}

	dsn := fmt.Sprintf(
		"host=%s user=%s password=%s dbname=%s port=%s sslmode=%s TimeZone=%s",
		cfg.Host,
		cfg.User,
		cfg.Password,
		cfg.Name,
		port,
		sslMode,
		timeZone,
	)

	return dsn, nil
}

// Open opens a postgres-backed gorm DB using the provided configuration.
func (f PostgresFactory) Open(cfg DBConfig) (*gorm.DB, error) {
	dsn, err := BuildPostgresDSN(cfg)
	if err != nil {
		return nil, err
	}

	gormCfg := f.GormConfig
	if gormCfg == nil {
		gormCfg = &gorm.Config{}
	}

	if gormCfg.Logger == nil {
		gormCfg.Logger = newFilteredGormLogger(gormlogger.New(
			log.New(os.Stdout, "\r\n", log.LstdFlags),
			gormlogger.Config{
				LogLevel:                  gormlogger.Warn,
				IgnoreRecordNotFoundError: true,
			},
		))
	}

	return gorm.Open(postgres.Open(dsn), gormCfg)
}

// InitDB opens the explicit runtime DB handle with the provided factory and config.
func InitDB(cfg DBConfig, factory DBFactory) (*gorm.DB, error) {
	if factory == nil {
		factory = PostgresFactory{}
	}

	conn, err := factory.Open(cfg)
	if err != nil {
		return nil, fmt.Errorf("open db: %w", err)
	}
	if conn == nil {
		return nil, fmt.Errorf("open db: factory returned nil db")
	}
	if err := ConfigureDBPool(conn, cfg); err != nil {
		return nil, fmt.Errorf("configure db pool: %w", err)
	}
	return conn, nil
}

// ConfigureDBPool applies runtime-owned connection pool and lifetime policy.
func ConfigureDBPool(db *gorm.DB, cfg DBConfig) error {
	if db == nil {
		return fmt.Errorf("database handle unavailable")
	}

	sqlDB, err := db.DB()
	if err != nil {
		return fmt.Errorf("sql db handle unavailable: %w", err)
	}

	sqlDB.SetMaxOpenConns(normalizeNonNegative(cfg.MaxOpenConns))
	sqlDB.SetMaxIdleConns(normalizeNonNegative(cfg.MaxIdleConns))
	sqlDB.SetConnMaxLifetime(normalizeNonNegativeDuration(cfg.ConnMaxLifetime))
	sqlDB.SetConnMaxIdleTime(normalizeNonNegativeDuration(cfg.ConnMaxIdleTime))
	return nil
}

// CheckDBReadiness verifies that the backing SQL connection is reachable for request handling.
func CheckDBReadiness(ctx context.Context, db *gorm.DB) error {
	if db == nil {
		return fmt.Errorf("database handle unavailable")
	}
	if ctx == nil {
		ctx = context.Background()
	}

	sqlDB, err := db.DB()
	if err != nil {
		return fmt.Errorf("sql db handle unavailable: %w", err)
	}
	if err := sqlDB.PingContext(ctx); err != nil {
		return fmt.Errorf("database ping failed: %w", err)
	}

	return nil
}

// CloseDB closes the underlying SQL connection pool during runtime shutdown.
func CloseDB(db *gorm.DB) error {
	if db == nil {
		return nil
	}

	sqlDB, err := db.DB()
	if err != nil {
		return fmt.Errorf("sql db handle unavailable: %w", err)
	}
	if err := sqlDB.Close(); err != nil {
		return fmt.Errorf("close db: %w", err)
	}
	return nil
}

// SetDB stores a process-global handle for legacy tests and narrow migration bridges.
//
// Production startup should pass the DB handle explicitly from InitDB instead of using
// this fallback.
func SetDB(conn *gorm.DB) {
	dbMu.Lock()
	db = conn
	dbMu.Unlock()
}

// GetDB returns the legacy process-global database connection.
//
// Production startup should pass the DB handle explicitly from InitDB instead of using
// this fallback.
func GetDB() *gorm.DB {
	dbMu.RLock()
	defer dbMu.RUnlock()
	return db
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if trimmed := strings.TrimSpace(v); trimmed != "" {
			return trimmed
		}
	}
	return ""
}

func intFromEnv(defaultValue int, keys ...string) int {
	value := firstExistingEnv(keys...)
	if value == "" {
		return defaultValue
	}
	parsed, err := strconv.Atoi(value)
	if err != nil {
		return defaultValue
	}
	return parsed
}

func durationFromEnv(defaultValue time.Duration, keys ...string) time.Duration {
	value := firstExistingEnv(keys...)
	if value == "" {
		return defaultValue
	}
	parsed, err := time.ParseDuration(value)
	if err != nil {
		return defaultValue
	}
	return parsed
}

