package security

import (
	"encoding/json"
	"net/http"
)

const (
	RuntimeReasonInternalError    = "INTERNAL_ERROR"
	RuntimeReasonLoginRateLimited = "LOGIN_RATE_LIMITED"
	RuntimeReasonMethodNotAllowed = "METHOD_NOT_ALLOWED"
	RuntimeReasonRateLimited      = "RATE_LIMITED"

	RuntimeErrorTypeInternal         = "runtime.internal"
	RuntimeErrorTypeMethodNotAllowed = "http.method_not_allowed"
	RuntimeErrorTypePanic            = "exception.panic"
	RuntimeErrorTypeRateLimited      = "http.rate_limited"
)

// RuntimeFailureResponse is the public runtime-boundary failure envelope.
type RuntimeFailureResponse struct {
	OK     bool   `json:"ok"`
	Reason string `json:"reason"`
}

// RuntimeFailureErrorType returns the stable telemetry classification for
// runtime-owned HTTP failures. It is intentionally independent from public
// response reason strings.
func RuntimeFailureErrorType(statusCode int) (string, bool) {
	switch statusCode {
	case http.StatusMethodNotAllowed:
		return RuntimeErrorTypeMethodNotAllowed, true
	case http.StatusTooManyRequests:
		return RuntimeErrorTypeRateLimited, true
	case http.StatusInternalServerError:
		return RuntimeErrorTypeInternal, true
	default:
		return "", false
	}
}

// WriteMethodNotAllowed writes the shared runtime-owned 405 response.
func WriteMethodNotAllowed(w http.ResponseWriter) {
	writeRuntimeFailure(w, http.StatusMethodNotAllowed, RuntimeReasonMethodNotAllowed)
}

// WriteRateLimited writes the shared runtime-owned 429 response.
func WriteRateLimited(w http.ResponseWriter, reason string) {
	if reason == "" {
		reason = RuntimeReasonRateLimited
	}
	writeRuntimeFailure(w, http.StatusTooManyRequests, reason)
}

// WriteInternalServerError writes the shared sanitized runtime-owned 500 response.
func WriteInternalServerError(w http.ResponseWriter) {
	writeRuntimeFailure(w, http.StatusInternalServerError, RuntimeReasonInternalError)
}

func writeRuntimeFailure(w http.ResponseWriter, statusCode int, reason string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	_ = json.NewEncoder(w).Encode(RuntimeFailureResponse{
		OK:     false,
		Reason: reason,
	})
}

func LogWarn(context, function, message string) {
	standard.log(3, "WARN", context, message, Operation(function))
}

// LogError retains the older call shape while emitting the stable runtime vocabulary.
func LogError(context, function string, err error) {
	fields := []Field{Operation(function)}
	if err != nil {
		fields = append(fields, Err(err))
	}

	standard.log(3, "ERROR", context, failureMessage(function), fields...)
}

func (l *RuntimeLogger) log(skip int, level, component, message string, fields ...Field) {
	if l == nil || l.sink == nil {
		return
	}

	values := map[string]string{}
	if component = redactSensitiveText(strings.TrimSpace(component)); component != "" {
		values[FieldComponent] = component
	}

	for _, field := range fields {
		key := normalizeKey(field.Key)
		if key == "" {
			continue
		}
		values[key] = sanitizeFieldValue(key, field.Value)
	}

	if source, ok := callerSource(skip); ok {
		values[FieldSource] = source
	}

	parts := []string{
		"level=" + level,
		"msg=" + strconv.Quote(redactSensitiveText(strings.TrimSpace(message))),
	}

	orderedKeys := []string{
		FieldComponent,
		FieldOperation,
		FieldRequestID,
		FieldTraceID,
		FieldSpanID,
		FieldTraceFlags,
		FieldMethod,
		FieldPath,
		FieldStatusCode,
		FieldDurationMS,
		FieldAddress,
		FieldErrorType,
		FieldException,
		FieldError,
		FieldSource,
	}

	used := make(map[string]struct{}, len(orderedKeys))
	for _, key := range orderedKeys {
		value, ok := values[key]
		if !ok || value == "" {
			continue
		}
		parts = append(parts, formatField(key, value))
		used[key] = struct{}{}
	}

	extraKeys := make([]string, 0, len(values))
	for key, value := range values {
		if value == "" {
			continue
		}
		if _, ok := used[key]; ok {
			continue
		}
		extraKeys = append(extraKeys, key)
	}
	sort.Strings(extraKeys)

	for _, key := range extraKeys {
		parts = append(parts, formatField(key, values[key]))
	}

	l.sink.Println(strings.Join(parts, " "))
}

func callerSource(skip int) (string, bool) {
	_, file, line, ok := runtime.Caller(skip)
	if !ok {
		return "", false
	}

	return filepath.Base(file) + ":" + strconv.Itoa(line), true
}

func formatField(key, value string) string {
	return key + "=" + strconv.Quote(value)
}

func failureMessage(operation string) string {
	operation = strings.TrimSpace(operation)
	if operation == "" {
		return "operation failed"
	}

	return operation + " failed"
}

func sanitizeFieldValue(key, value string) string {
	if sensitiveFieldKey(key) {
		return redactedValue
	}

	return redactSensitiveText(strings.TrimSpace(value))
}

func redactSensitiveText(value string) string {
	if value == "" {
		return ""
	}

	redacted := bearerSecretPattern.ReplaceAllString(value, "Bearer "+redactedValue)
	redacted = keyValueSecretPattern.ReplaceAllString(redacted, "${1}"+redactedValue)
	return redacted
}

func sensitiveFieldKey(key string) bool {
	normalized := strings.ReplaceAll(normalizeKey(key), "_", "")
	for _, fragment := range []string{
		"password",
		"passwd",
		"pwd",
		"token",
		"secret",
		"apikey",
		"authorization",
		"cookie",
		"setcookie",
	} {
		if strings.Contains(normalized, fragment) {
			return true
		}
	}

	return false
}

func normalizeKey(key string) string {
	key = strings.TrimSpace(strings.ToLower(key))
	if key == "" {
		return ""
	}

	var builder strings.Builder
	builder.Grow(len(key))

	lastUnderscore := false
	for _, r := range key {
		switch {
		case r >= 'a' && r <= 'z':
			builder.WriteRune(r)
			lastUnderscore = false
		case r >= '0' && r <= '9':
			builder.WriteRune(r)
			lastUnderscore = false
		case r == '_' || r == '-' || r == ' ':
			if lastUnderscore {
				continue
			}
			builder.WriteByte('_')
			lastUnderscore = true
		}
	}

	return strings.Trim(builder.String(), "_")
}

func validTraceID(value string) bool {
	return validHex(value, 32) && !allZero(value)
}

func validSpanID(value string) bool {
	return validHex(value, 16) && !allZero(value)
}

func validHex(value string, length int) bool {
	if len(value) != length {
		return false
	}

	for _, r := range value {
		switch {
		case r >= '0' && r <= '9':
		case r >= 'a' && r <= 'f':
		case r >= 'A' && r <= 'F':
		default:
			return false
		}
	}

	return true
}

func allZero(value string) bool {
	for _, r := range value {
		if r != '0' {
			return false
		}
	}

	return true
}

package main

import (
	"net/http"

	appenv "socialpredict/internal/app/env"
	appruntime "socialpredict/internal/app/runtime"
	authsvc "socialpredict/internal/service/auth"
	"socialpredict/logger"
	"socialpredict/migration"
	_ "socialpredict/migration/migrations" // <-- side-effect import: registers migrations via init()
	"socialpredict/seed"
	"socialpredict/server"
	"socialpredict/setup"
)

func main() {
	// Secure endpoint example
	http.Handle("/secure", authsvc.Authenticate(http.HandlerFunc(secureEndpoint)))

	readiness := appruntime.NewReadiness()

	// Load local development env overrides from .env.dev when present.
	if err := appenv.LoadDevFile(); err != nil {
		logger.Warn("startup", "development environment override not loaded", logger.Operation("LoadDevFile"), logger.Err(err))
	}

	dbCfg, err := appruntime.LoadDBConfigFromEnv()
	if err != nil {
		logger.Fatal("startup", "database configuration unavailable", err, logger.Operation("LoadDBConfigFromEnv"))
	}

	db, err := appruntime.InitDB(dbCfg, appruntime.PostgresFactory{})
	if err != nil {
		logger.Fatal("startup", "database initialization failed", err, logger.Operation("InitDB"))
	}
	defer func() {
		if err := appruntime.CloseDB(db); err != nil {
			logger.Warn("startup", "database shutdown reported a warning", logger.Operation("CloseDB"), logger.Err(err))
		}
	}()

	const MAX_ATTEMPTS = 20
	if err := seed.EnsureDBReady(db, MAX_ATTEMPTS); err != nil {
		logger.Fatal("startup", "database readiness check failed", err, logger.Operation("EnsureDBReady"))
	}

	configService, err := appruntime.LoadConfigService(setup.EmbeddedSource{})
	if err != nil {
		logger.Fatal("startup", "configuration service initialization failed", err, logger.Operation("LoadConfigService"))
	}

	securityConfig, err := appruntime.LoadSecurityConfigFromEnv()
	if err != nil {
		logger.Fatal("startup", "security configuration unavailable", err, logger.Operation("LoadSecurityConfigFromEnv"))
	}
	authsvc.ConfigureJWTSigningKey(securityConfig.JWTSigningKey)

	startupMode, err := appruntime.LoadStartupMutationModeFromEnv()
	if err != nil {
		logger.Fatal("startup", "startup mutation mode unavailable", err, logger.Operation("LoadStartupMutationModeFromEnv"))
	}

	shutdownConfig, err := appruntime.LoadShutdownConfigFromEnv()
	if err != nil {
		logger.Fatal("startup", "shutdown configuration unavailable", err, logger.Operation("LoadShutdownConfigFromEnv"))
	}

	if startupMode.Writer {
		logger.Info("startup", "startup writer enabled for database migrations and seeds", logger.Operation("StartupMutationMode"))
	} else {
		logger.Info("startup", "startup writer disabled; verifying database schema before serving", logger.Operation("StartupMutationMode"))
	}
	if err := runStartupMutations(db, configService, startupMode, startupMutationHooks{
		migrate:      migration.MigrateDB,
		verify:       migration.VerifyApplied,
		seedUsers:    seed.SeedUsers,
		seedHomepage: seed.SeedHomepage,
	}); err != nil {
		logger.Fatal("startup", "startup database mutation check failed", err, logger.Operation("RunStartupMutations"))
	}

	readiness.MarkReady()

	server.Start(openAPISpec, swaggerUIFS, db, configService, readiness, securityConfig, shutdownConfig)
}

