func requestBoundaryFields(r *http.Request, requestID string, statusCode int, duration time.Duration, errorType string, extractors ...ClientIdentityExtractor) []logger.Field {
	clientIdentity := NewClientIdentityExtractor(false)
	if len(extractors) > 0 {
		clientIdentity = extractors[0]
	}
	fields := []logger.Field{
		logger.Operation("RequestBoundary"),
		logger.RequestID(requestID),
		logger.Method(requestMethod(r)),
		logger.Path(requestPath(r)),
		logger.StatusCode(statusCode),
		logger.DurationMS(duration),
	}

	}
	if address := strings.TrimSpace(clientIdentity.Extract(r)); address != "" {
		fields = append(fields, logger.Address(address))
	}
	fields = append(fields, logger.TraceContextFromTraceparent(r.Header.Get("Traceparent"))...)
	if strings.TrimSpace(errorType) != "" {
		fields = append(fields, logger.ErrorType(errorType))
	}

	return fields
}

func writeRecoveredPanicResponse(w http.ResponseWriter) {
	WriteInternalServerError(w)
}

func runtimeFailureErrorType(statusCode int) string {
	errorType, ok := RuntimeFailureErrorType(statusCode)
	if !ok {
		return ""
	}
	return errorType
}

func defaultRequestID() string {
	var raw [16]byte
	if _, err := crand.Read(raw[:]); err == nil {
		return hex.EncodeToString(raw[:])
	}

	return strconv.FormatInt(time.Now().UnixNano(), 16)
}

func incomingRequestID(r *http.Request, newRequestID func() string) string {
	if r != nil {
		if requestID := strings.TrimSpace(r.Header.Get(requestIDHeader)); requestID != "" {
			return requestID
		}
	}

	return newRequestID()
}

func requestMethod(r *http.Request) string {
	if r == nil {
		return ""

	}
}

func TestEventAndStateFieldsUseStableRuntimeVocabulary(t *testing.T) {
	var buffer bytes.Buffer
	logger := newRuntimeLogger(&buffer, func(int) {})

	logger.Info("runtime", "readiness opened", Event(EventReadinessOpen), Operation("MarkReady"), State("open"))

	output := buffer.String()
	for _, want := range []string{
		`component="runtime"`,
		`event="readiness.open"`,
		`operation="MarkReady"`,
		`state="open"`,
	} {
		if !strings.Contains(output, want) {
			t.Fatalf("expected %q in output, got %q", want, output)
		}
	}
}

func TestFatalLogsAndUsesInjectedExit(t *testing.T) {
	var (
		buffer   bytes.Buffer
		exitCode = -1
	)
	logger := newRuntimeLogger(&buffer, func(code int) {
		exitCode = code
	})

	logger.Fatal(
		"startup",
		"database initialization failed",
		errors.New("password=swordfish"),
		Event(EventStartupIncompatibility),
		Operation("InitDB"),
		ErrorType(EventStartupIncompatibility),
	)

	output := buffer.String()
	if exitCode != 1 {
		t.Fatalf("expected exit code 1, got %d", exitCode)
	}
	if !strings.Contains(output, "level=FATAL") {
		t.Fatalf("expected FATAL level in output, got %q", output)
	}
	if !strings.Contains(output, `operation="InitDB"`) {
		t.Fatalf("expected operation field in output, got %q", output)
	}

	}
	if !strings.Contains(output, `event="startup.incompatibility"`) {
		t.Fatalf("expected startup event field in output, got %q", output)
	}
	if !strings.Contains(output, `error_type="startup.incompatibility"`) {
		t.Fatalf("expected startup error_type field in output, got %q", output)
	}
	if !strings.Contains(output, `error="password=[REDACTED]"`) {
		t.Fatalf("expected redacted error field in output, got %q", output)
	}
}

